t.script:
function toggleAllMosques(cb){ const flag = document.getElementById("all_mosques_flag"); flag.value
                = cb.checked ? "1" : "0"; document.querySelectorAll(".mosque-checkbox").forEach(function(item){
                item.checked = cb.checked; item.disabled = cb.checked; }); } function filterMosques(){ const search =
                document.getElementById("mosque_search") .value .toLowerCase() .trim();
                document.querySelectorAll(".mosque-item").forEach(function(item){ const text = item.dataset.name || "";
                if(text.indexOf(search) >= 0){ item.style.display = ""; }else{ item.style.display = "none"; } }); }
                document.addEventListener("DOMContentLoaded", function(){
                document.querySelectorAll(".mosque-checkbox").forEach(function(box){ box.addEventListener("change",
                function(){ const checked = document.querySelectorAll(".mosque-checkbox:checked").length;
                document.getElementById("all_mosques").checked = false;
                document.getElementById("all_mosques_flag").value = "0"; this.disabled = false; }); }); });

