t.script:
document.querySelectorAll('input[name="scope"]').forEach(r => {
r.addEventListener('change', () => {
const wrap = document.getElementById('mosque-select-wrap');
if (wrap) wrap.style.display = r.value === 'specific' ? 'block' : 'none';
});
});

